// src/pages/LabourDashboard.jsx

import { useEffect, useState } from "react";

import axios from "axios";

import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [requests, setRequests] =
    useState([]);

  const [price, setPrice] =
    useState({});

  useEffect(() => {

    getRequests();

  }, []);

  const getRequests = async () => {

    const res = await axios.get(

      `http://localhost:5000/api/request/labour/${user._id}`

    );

    setRequests(res.data);
  };

  const respondRequest =
    async (id, action) => {

      await axios.put(

        `http://localhost:5000/api/request/labour-response/${id}`,

        {
          price: price[id] || 0,
          action
        }

      );

      getRequests();
    };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.card}>

          <h2 style={styles.heading}>
            Request Received
          </h2>

          {requests.map((req) => (

            <div
              key={req._id}
              style={styles.requestBox}
            >

              <h3>
                {req.customerName}
              </h3>

              <p>
                Work:
                {" "}
                {req.workType}
              </p>

              <p>
                Location:
                {" "}
                {req.location}
              </p>

              <p>
                Date:
                {" "}
                {req.date}
              </p>

              <p>
                Status:
                {" "}
                {req.status}
              </p>

              <p>
                Customer Decision:
                {" "}
                {req.customerDecision}
              </p>

              <input
                type="number"
                placeholder="Enter Price"
                style={styles.input}
                onChange={(e) =>
                  setPrice({
                    ...price,
                    [req._id]:
                      e.target.value
                  })
                }
              />

              {req.status ===
                "Pending" && (

                <div
                  style={styles.btnRow}
                >

                  <button
                    style={
                      styles.acceptBtn
                    }

                    onClick={() =>
                      respondRequest(
                        req._id,
                        "Accepted"
                      )
                    }
                  >
                    Accept
                  </button>

                  <button
                    style={
                      styles.rejectBtn
                    }

                    onClick={() =>
                      respondRequest(
                        req._id,
                        "Rejected"
                      )
                    }
                  >
                    Reject
                  </button>

                </div>

              )}

              {req.feedback && (

                <div
                  style={styles.feedbackBox}
                >

                  <h4>
                    Rating:
                    {" "}
                    {req.feedback.rating}
                    /5
                  </h4>

                  <p>
                    {req.feedback.comment}
                  </p>

                </div>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh"
  },

  container: {
    padding: "30px"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "16px",
    boxShadow:
      "0 4px 12px rgba(0,0,0,0.05)"
  },

  heading: {
    marginBottom: "20px"
  },

  requestBox: {
    border: "1px solid #e5e7eb",
    borderRadius: "12px",
    padding: "18px",
    marginBottom: "20px"
  },

  input: {
    width: "100%",
    padding: "12px",
    marginTop: "10px",
    borderRadius: "8px",
    border: "1px solid #d1d5db",
    boxSizing: "border-box"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "14px"
  },

  acceptBtn: {
    flex: 1,
    padding: "12px",
    background: "green",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "12px",
    background: "red",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  feedbackBox: {
    marginTop: "16px",
    background: "#f9fafb",
    padding: "14px",
    borderRadius: "10px"
  }

};
